solution.code:
def allocation_num(total_bytes, partitions):
    size = total_bytes // partitions
    result = []
    for i in range(partitions):
        start = i * size + 1
        end = total_bytes if i == partitions - 1 else (i + 1) * size
        result.append(f"{start}-{end}")
    return result

if __name__ == "__main__":
    print(allocation_num(100, 4))
